import java.io.File;
import java.util.Scanner;

public class SecurePathTraversal {
    private static final String BASE_PATH = "/path/to/directory/";

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter file name: ");
        String fileName = scanner.nextLine();

        if (isValidFileName(fileName)) {
            File file = new File(BASE_PATH + fileName);

            if (file.exists() && file.isFile()) {
                System.out.println("File exists.");
                // Perform some operation with the file
            } else {
                System.out.println("File does not exist or is not a regular file.");
            }
        } else {
            System.out.println("Invalid file name.");
        }

        scanner.close();
    }

    private static boolean isValidFileName(String fileName) {
        // Perform additional validation here based on your requirements
        // For example, you can check for allowed characters or patterns
        return !fileName.contains("..");
    }
}

